/**
 * Server-only module: SQLite persistence + password hashing + session management.
 *
 * Everything in this file runs exclusively on the server (it is a `*.server.ts`
 * module and is only ever imported from `routeAction$` / `routeLoader$` /
 * `onRequest` boundaries), so none of this code can leak into client bundles.
 */
import { createHash, randomBytes, scryptSync, timingSafeEqual } from "node:crypto";
import { mkdirSync } from "node:fs";
import { dirname, join } from "node:path";
import Database from "better-sqlite3";

export type User = {
  id: number;
  username: string;
};

const SCRYPT_KEYLEN = 64;
const SCRYPT_SALTLEN = 16;
const SCRYPT_PARAMS: Record<string, number> = { N: 16384, r: 8, p: 1 } as const;

// Store the database file under the project directory so everything stays local.
const DB_PATH = join(process.cwd(), "data", "auth.db");

let db: Database.Database | null = null;

function getDb(): Database.Database {
  if (db) return db;
  mkdirSync(dirname(DB_PATH), { recursive: true });
  const database = new Database(DB_PATH);
  database.pragma("journal_mode = WAL");
  initSchema(database);
  seed(database);
  db = database;
  return database;
}

function initSchema(database: Database.Database) {
  database.exec(`
    CREATE TABLE IF NOT EXISTS users (
      id         INTEGER PRIMARY KEY AUTOINCREMENT,
      username   TEXT NOT NULL UNIQUE,
      salt       TEXT NOT NULL,
      hash       TEXT NOT NULL
    );

    CREATE TABLE IF NOT EXISTS sessions (
      token      TEXT PRIMARY KEY,
      username   TEXT NOT NULL,
      created_at INTEGER NOT NULL
    );
  `);
}

function seed(database: Database.Database) {
  const existing = database
    .prepare("SELECT id FROM users WHERE username = ?")
    .get("alice");
  if (existing) return;
  const { salt, hash } = hashPassword("s3cret-pass");
  database
    .prepare("INSERT INTO users (username, salt, hash) VALUES (?, ?, ?)")
    .run("alice", salt, hash);
}

/* ------------------------------------------------------------------ */
/* Password hashing (Node built-in crypto, scrypt)                    */
/* ------------------------------------------------------------------ */

export function hashPassword(password: string): {
  salt: string;
  hash: string;
} {
  const salt = randomBytes(SCRYPT_SALTLEN);
  const hash = scryptSync(password, salt, SCRYPT_KEYLEN, SCRYPT_PARAMS);
  return { salt: salt.toString("hex"), hash: hash.toString("hex") };
}

export function verifyPassword(
  password: string,
  saltHex: string,
  hashHex: string,
): boolean {
  const salt = Buffer.from(saltHex, "hex");
  const expected = Buffer.from(hashHex, "hex");
  const actual = scryptSync(password, salt, SCRYPT_KEYLEN, SCRYPT_PARAMS);
  return (
    actual.length === expected.length &&
    timingSafeEqual(actual, expected)
  );
}

/* ------------------------------------------------------------------ */
/* Users                                                              */
/* ------------------------------------------------------------------ */

export function authenticateUser(
  username: string,
  password: string,
): User | null {
  const database = getDb();
  const row = database
    .prepare("SELECT id, username, salt, hash FROM users WHERE username = ?")
    .get(username) as
    | { id: number; username: string; salt: string; hash: string }
    | undefined;
  if (!row) return null;
  if (!verifyPassword(password, row.salt, row.hash)) return null;
  return { id: row.id, username: row.username };
}

/* ------------------------------------------------------------------ */
/* Sessions                                                           */
/* ------------------------------------------------------------------ */

function newToken(): string {
  // 32 random bytes -> 64 hex chars. Also fold in a sha256 of randomness for
  // a bit of extra entropy, though randomBytes alone is plenty.
  return (
    randomBytes(32).toString("hex") +
    createHash("sha256").update(randomBytes(16)).digest("hex")
  );
}

export function createSession(username: string): string {
  const database = getDb();
  const token = newToken();
  database
    .prepare(
      "INSERT INTO sessions (token, username, created_at) VALUES (?, ?, ?)",
    )
    .run(token, username, Date.now());
  return token;
}

export function getSessionUser(token: string): string | null {
  const database = getDb();
  const row = database
    .prepare("SELECT username FROM sessions WHERE token = ?")
    .get(token) as { username: string } | undefined;
  return row ? row.username : null;
}

export function deleteSession(token: string): void {
  const database = getDb();
  database.prepare("DELETE FROM sessions WHERE token = ?").run(token);
}

import { component$ } from "@builder.io/qwik";
import {
  type DocumentHead,
  Form,
  routeAction$,
  z,
  zod$,
} from "@builder.io/qwik-city";
import { authenticateUser, createSession } from "~/db.server";

export const useLogin = routeAction$(
  async (values, event) => {
    const username = values.username.trim();
    const password = values.password;

    const user = authenticateUser(username, password);
    if (!user) {
      // Do NOT set the session cookie. Re-render /login with an error.
      return {
        error: "Invalid username or password",
      };
    }

    const token = createSession(user.username);
    event.cookie.set("session", token, {
      httpOnly: true,
      path: "/",
      sameSite: "lax",
    });

    throw event.redirect(302, "/dashboard");
  },
  zod$(
    z.object({
      username: z.string(),
      password: z.string(),
    }),
  ),
);

export default component$(() => {
  const login = useLogin();

  return (
    <main style={{ maxWidth: "24rem", margin: "4rem auto" }}>
      <h1>Sign in</h1>

      {login.value?.error && (
        <p
          style={{
            color: "#b00020",
            border: "1px solid #b00020",
            padding: "0.5rem 0.75rem",
            borderRadius: "0.25rem",
          }}
        >
          {login.value.error}
        </p>
      )}

      <Form action={login}>
        <div style={{ marginBottom: "1rem" }}>
          <label
            for="username"
            style={{ display: "block", marginBottom: "0.25rem" }}
          >
            Username
          </label>
          <input
            id="username"
            name="username"
            type="text"
            autoComplete="username"
            required
            style={{ width: "100%", padding: "0.4rem" }}
          />
        </div>

        <div style={{ marginBottom: "1rem" }}>
          <label
            for="password"
            style={{ display: "block", marginBottom: "0.25rem" }}
          >
            Password
          </label>
          <input
            id="password"
            name="password"
            type="password"
            autoComplete="current-password"
            required
            style={{ width: "100%", padding: "0.4rem" }}
          />
        </div>

        <button type="submit" style={{ padding: "0.5rem 1rem" }}>
          Login
        </button>
      </Form>
    </main>
  );
});

export const head: DocumentHead = {
  title: "Login",
};

import { component$, Slot } from "@builder.io/qwik";
import { type RequestHandler } from "@builder.io/qwik-city";
import { getSessionUser } from "~/db.server";

/**
 * Layout middleware guarding every route inside the `(app)` route group.
 *
 * A request without a valid `session` cookie is redirected to `/login`.
 * This keeps `/login` itself public (it lives outside this group) while
 * protecting `/dashboard` and any other routes added under `(app)`.
 */
export const onRequest: RequestHandler = async (event) => {
  const token = event.cookie.get("session")?.value;
  if (!token) {
    throw event.redirect(302, "/login");
  }

  const username = getSessionUser(token);
  if (!username) {
    // The cookie is present but no matching session exists — clear it and
    // bounce back to the login page.
    event.cookie.delete("session", { path: "/" });
    throw event.redirect(302, "/login");
  }
};

export default component$(() => {
  return <Slot />;
});

import { component$ } from "@builder.io/qwik";
import {
  type DocumentHead,
  Form,
  routeAction$,
  routeLoader$,
} from "@builder.io/qwik-city";
import { deleteSession, getSessionUser } from "~/db.server";

/**
 * Loads the authenticated user for the dashboard. The layout middleware
 * (`onRequest` in `src/routes/(app)/layout.tsx`) has already verified the
 * session cookie by the time this runs, but we re-resolve it here so the
 * page can display the logged-in username.
 */
export const useUser = routeLoader$(async (event) => {
  const token = event.cookie.get("session")?.value;
  if (!token) throw event.redirect(302, "/login");
  const username = getSessionUser(token);
  if (!username) throw event.redirect(302, "/login");
  return { username };
});

export const useLogout = routeAction$(async (_values, event) => {
  const token = event.cookie.get("session")?.value;
  if (token) {
    deleteSession(token);
  }
  event.cookie.delete("session", { path: "/" });
  throw event.redirect(302, "/login");
});

export default component$(() => {
  const user = useUser();
  const logout = useLogout();

  return (
    <main style={{ maxWidth: "32rem", margin: "4rem auto" }}>
      <h1>Dashboard</h1>
      <p>
        Welcome, <strong>{user.value.username}</strong>!
      </p>

      <Form action={logout}>
        <button type="submit" style={{ padding: "0.4rem 1rem" }}>
          Logout
        </button>
      </Form>
    </main>
  );
});

export const head: DocumentHead = {
  title: "Dashboard",
};

